"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import {
  fetchBanners,
  getCategoryNameFromBanner,
  getVendorIdFromBanner,
} from "@/apis/banners/banners";

// niche dikhne wali circular category icons - apni categories daal do
const categoryIcons = [
  {
    label: "Headsets",
    image:
      "https://images.unsplash.com/photo-1505740420928-5e560c06d30e?q=80&w=300&auto=format&fit=crop",
    link: "/shop?category=Audio",
  },
  {
    label: "Charging accessories",
    image:
      "https://images.unsplash.com/photo-1583863788434-e58a36330cf0?q=80&w=300&auto=format&fit=crop",
    link: "/shop?category=Accessories",
  },
  {
    label: "Cases and covers",
    image:
      "https://images.unsplash.com/photo-1592286927505-1def25115558?q=80&w=300&auto=format&fit=crop",
    link: "/shop?category=Mobiles",
  },
  {
    label: "Screen protectors",
    image:
      "https://images.unsplash.com/photo-1610945265064-0e34e5519bbf?q=80&w=300&auto=format&fit=crop",
    link: "/shop?category=Mobiles",
  },
  {
    label: "Mobile holders",
    image:
      "https://images.unsplash.com/photo-1576267423445-b2e0074d68a4?q=80&w=300&auto=format&fit=crop",
    link: "/shop?category=Accessories",
  },
];

// banner.bg API me nahi aata, isliye index ke hisab se rotate karne ke liye gradients
const bgGradients = [
  "from-[#1f3fae] via-[#2451d6] to-[#3a6cf0]",
  "from-[#7a1f3d] via-[#9c2c4f] to-[#c2436a]",
  "from-[#0f4c3a] via-[#13684f] to-[#1a8a68]",
  "from-[#5b1f8f] via-[#7a2cae] to-[#9c43c2]",
];

export default function FestiveOfferBanner() {
  const [banners, setBanners] = useState([]);
  const [index, setIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  // API se banners fetch karo
  useEffect(() => {
    let isMounted = true;

    async function loadBanners() {
      try {
        setLoading(true);
        const data = await fetchBanners();
        if (isMounted) {
          setBanners(data);
          setError(false);
        }
      } catch (err) {
        console.error("Banner fetch failed:", err);
        if (isMounted) setError(true);
      } finally {
        if (isMounted) setLoading(false);
      }
    }

    loadBanners();

    return () => {
      isMounted = false;
    };
  }, []);

  // auto slide har 4 second me
  useEffect(() => {
    if (banners.length <= 1) return undefined;

    const timer = setInterval(() => {
      setIndex((prev) => (prev + 1) % banners.length);
    }, 4000);

    return () => clearInterval(timer);
  }, [banners.length]);

  // agar loading hai ya koi banner nahi mila to kuch bhi render mat karo
  if (loading) {
    return (
      <section className="mt-6 mx-auto w-full max-w-[1040px] px-4">
        <div className="h-[260px] w-full animate-pulse rounded-none bg-zinc-200 md:h-[300px]" />
      </section>
    );
  }

  if (error || banners.length === 0) {
    return null;
  }

  const banner = banners[index];

  // banner se category name aur vendorId nikal lo (helper functions se)
  const categoryName = getCategoryNameFromBanner(banner);
  const vendorId = getVendorIdFromBanner(banner);

  // shop page ka link - category ke hisab se filter hoga
  const shopLink = categoryName
    ? `/shop?category=${encodeURIComponent(categoryName)}${
        vendorId ? `&vendorId=${encodeURIComponent(vendorId)}` : ""
      }`
    : "/shop";

  return (
    <section className="mt-6 mx-auto w-full max-w-[1040px] px-4">
      {/* MAIN BANNER */}
      <Link href={shopLink} className="block">
        <div
          className={`relative overflow-hidden bg-gradient-to-br ${
            bgGradients[index % bgGradients.length]
          } shadow-[0_15px_60px_rgba(0,0,0,0.12)] transition-colors duration-700`}
        >
          <AnimatePresence mode="wait">
            <motion.div
              key={banner._id || index}
              initial={{ opacity: 0, x: 30 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -30 }}
              transition={{ duration: 0.5, ease: "easeInOut" }}
              className="relative z-10 grid items-center gap-5 px-5 py-8 md:grid-cols-[0.95fr_1.05fr] md:px-8 md:py-10 lg:px-10"
            >
              {/* LEFT - TEXT */}
              <div>
                {/* category name label ke upar */}
                <p className="text-base font-medium text-white/85 md:text-lg">
                  {categoryName || "Special Offer"}
                </p>

                {/* banner ka title - API se "title" field */}
                <h2 className="mt-1 text-[28px] font-black leading-[1.1] text-white md:text-[40px]">
                  {banner.title}
                </h2>

                {/* vendor company name - "Powered by X" */}
                {banner.vendorId?.companyname && (
                  <p className="mt-2 text-xs font-medium tracking-wide text-white/70 md:text-sm">
                    Powered by {banner.vendorId.companyname}
                  </p>
                )}

                {/* discount percentage - API se "discount_percentage" */}
                {typeof banner.discount_percentage === "number" && (
                  <h3 className="mt-4 text-2xl font-black text-white md:text-3xl">
                    Up to {banner.discount_percentage}% off
                  </h3>
                )}

                <p className="text-sm font-medium text-white/85 md:text-base">
                  {categoryName}
                </p>
              </div>

              {/* RIGHT - IMAGE */}
              <div className="relative h-[220px] w-full md:h-[260px] lg:h-[278px]">
                <Image
                  src={banner.image_url}
                  alt={banner.title || categoryName || "Banner"}
                  fill
                  className="object-cover"
                  sizes="(max-width: 767px) 100vw, 50vw"
                  unoptimized
                />
              </div>
            </motion.div>
          </AnimatePresence>

          {/* DOTS */}
          {banners.length > 1 && (
            <div className="absolute bottom-3 left-1/2 z-20 flex -translate-x-1/2 justify-center gap-2">
              {banners.map((_, i) => (
                <button
                  key={i}
                  onClick={(e) => {
                    e.preventDefault(); // link ke andar hai isliye navigation rokna zaroori hai
                    e.stopPropagation();
                    setIndex(i);
                  }}
                  className={`transition-all ${
                    i === index
                      ? "h-2 w-7 rounded-full bg-white"
                      : "h-2 w-2 rounded-full bg-white/40"
                  }`}
                  aria-label={`Go to slide ${i + 1}`}
                />
              ))}
            </div>
          )}
        </div>
      </Link>

      {/* CATEGORY ICONS ROW */}
      <div className="mt-3 flex flex-wrap justify-start gap-x-6 gap-y-3 sm:gap-x-8">
        {categoryIcons.map((item) => (
          <Link
            key={item.label}
            href={item.link}
            className="group flex w-[72px] flex-col items-center gap-1.5 text-center sm:w-[88px]"
          >
            <div className="relative h-14 w-14 overflow-hidden rounded-full border border-black/5 bg-zinc-100 shadow-sm transition group-hover:shadow-md sm:h-16 sm:w-16">
              <Image
                src={item.image}
                alt={item.label}
                fill
                className="object-cover transition duration-300 group-hover:scale-110"
                sizes="64px"
              />
            </div>

            <span className="text-[11px] font-medium leading-tight text-zinc-700 group-hover:text-black sm:text-xs">
              {item.label}
            </span>
          </Link>
        ))}
      </div>
    </section>
  );
}